  <script>
    /* =========================================================================
       1. Inline WebGL Matrix & Math Helpers
       ========================================================================= */
    function createMat4() {
      return new Float32Array(16);
    }

    function identityMat4(out) {
      out.fill(0);
      out[0] = out[5] = out[10] = out[15] = 1;
      return out;
    }

    function perspectiveMat4(out, fovy, aspect, near, far) {
      const f = 1.0 / Math.tan(fovy / 2);
      const nf = 1.0 / (near - far);
      out.fill(0);
      out[0] = f / aspect;
      out[5] = f;
      out[10] = (far + near) * nf;
      out[11] = -1;
      out[14] = (2 * far * near) * nf;
      return out;
    }

    function rotateXMat4(out, a, rad) {
      const s = Math.sin(rad), c = Math.cos(rad);
      identityMat4(out);
      out[5] = c; out[6] = s;
      out[9] = -s; out[10] = c;
      return out;
    }

    function rotateYMat4(out, a, rad) {
      const s = Math.sin(rad), c = Math.cos(rad);
      identityMat4(out);
      out[0] = c; out[2] = -s;
      out[8] = s; out[10] = c;
      return out;
    }

    function multiplyMat4(out, a, b) {
      const tmp = new Float32Array(16);
      for (let i = 0; i < 4; i++) {
        for (let j = 0; j < 4; j++) {
          tmp[j * 4 + i] = 
            a[0 * 4 + i] * b[j * 4 + 0] +
            a[1 * 4 + i] * b[j * 4 + 1] +
            a[2 * 4 + i] * b[j * 4 + 2] +
            a[3 * 4 + i] * b[j * 4 + 3];
        }
      }
      out.set(tmp);
      return out;
    }

    function mat3FromMat4(out, a) {
      out[0] = a[0]; out[1] = a[1]; out[2] = a[2];
      out[3] = a[4]; out[4] = a[5]; out[5] = a[6];
      out[6] = a[8]; out[7] = a[9]; out[8] = a[10];
    }

    /* =========================================================================
       2. Procedural Texture Generators for Front & Back Faces
       ========================================================================= */
    function generateFaceTexture(type, metalType) {
      const canvas = document.createElement('canvas');
      canvas.width = 1024;
      canvas.height = 1024;
      const ctx = canvas.getContext('2d');
      const cx = 512, cy = 512, r = 480;

      // Color Schemes
      let baseGrad, textColor, rimColor, shadowColor;
      if (metalType === 'silver') {
        baseGrad = ['#ffffff', '#a8b2c1', '#515966'];
        textColor = '#ffffff';
        rimColor = '#d0d7de';
        shadowColor = 'rgba(0,0,0,0.8)';
      } else if (metalType === 'bronze') {
        baseGrad = ['#f5ae78', '#a85b24', '#472207'];
        textColor = '#ffd3ad';
        rimColor = '#cd7f32';
        shadowColor = 'rgba(0,0,0,0.85)';
      } else if (metalType === 'black') {
        baseGrad = ['#3a3f52', '#181a24', '#08090d'];
        textColor = '#f0c040';
        rimColor = '#f0c040';
        shadowColor = 'rgba(0,0,0,0.95)';
      } else { // Gold default
        baseGrad = ['#fff5b8', '#d4af37', '#6b4f0a'];
        textColor = '#fff8d0';
        rimColor = '#f0c040';
        shadowColor = 'rgba(0,0,0,0.85)';
      }

      // 1. Background Metallic Gradient
      const grad = ctx.createRadialGradient(cx - 100, cy - 100, 50, cx, cy, r);
      grad.addColorStop(0, baseGrad[0]);
      grad.addColorStop(0.5, baseGrad[1]);
      grad.addColorStop(1, baseGrad[2]);
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(cx, cy, r, 0, Math.PI * 2);
      ctx.fill();

      // 2. Beaded Ring Border
      const numBeads = 80;
      const beadRadius = 450;
      ctx.fillStyle = rimColor;
      for (let i = 0; i < numBeads; i++) {
        const ang = (i / numBeads) * Math.PI * 2;
        const bx = cx + beadRadius * Math.cos(ang);
        const by = cy + beadRadius * Math.sin(ang);
        ctx.beginPath();
        ctx.arc(bx, by, 6, 0, Math.PI * 2);
        ctx.fill();
      }

      // Concentric Security Circles
      ctx.strokeStyle = rimColor;
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(cx, cy, 435, 0, Math.PI * 2);
      ctx.arc(cx, cy, 330, 0, Math.PI * 2);
      ctx.stroke();

      if (type === 'front') {
        // --- FRONT FACE: Emblem ---
        // Curved Top Text
        drawArcText(ctx, "WASTED TOKEN MINT", cx, cy, 380, -Math.PI * 0.75, -Math.PI * 0.25, textColor, shadowColor, 44);
        // Curved Bottom Text
        drawArcText(ctx, "★ PROOF QUALITY • 2025 ★", cx, cy, 380, Math.PI * 0.25, Math.PI * 0.75, textColor, shadowColor, 36);

        // Center Emblem Shield / Crest
        ctx.save();
        ctx.translate(cx, cy);

        // Crown on Top
        ctx.fillStyle = textColor;
        ctx.shadowColor = shadowColor;
        ctx.shadowBlur = 10;
        ctx.shadowOffsetX = 3;
        ctx.shadowOffsetY = 5;

        ctx.beginPath();
        ctx.moveTo(-70, -120);
        ctx.lineTo(-100, -180);
        ctx.lineTo(-40, -150);
        ctx.lineTo(0, -210);
        ctx.lineTo(40, -150);
        ctx.lineTo(100, -180);
        ctx.lineTo(70, -120);
        ctx.closePath();
        ctx.fill();

        // Crown Jewels
        ctx.fillStyle = baseGrad[2];
        [-100, -40, 0, 40, 100].forEach((xPos, idx) => {
          const yPos = idx === 2 ? -210 : (idx === 1 || idx === 3 ? -150 : -180);
          ctx.beginPath();
          ctx.arc(xPos, yPos, 8, 0, Math.PI * 2);
          ctx.fill();
        });

        // Main Shield
        ctx.fillStyle = textColor;
        ctx.beginPath();
        ctx.moveTo(-120, -90);
        ctx.lineTo(120, -90);
        ctx.lineTo(120, 30);
        ctx.quadraticCurveTo(120, 140, 0, 190);
        ctx.quadraticCurveTo(-120, 140, -120, 30);
        ctx.closePath();
        ctx.fill();

        // Inner Shield Cutout
        ctx.fillStyle = baseGrad[2];
        ctx.beginPath();
        ctx.moveTo(-100, -75);
        ctx.lineTo(100, -75);
        ctx.lineTo(100, 25);
        ctx.quadraticCurveTo(100, 120, 0, 165);
        ctx.quadraticCurveTo(-100, 120, -100, 25);
        ctx.closePath();
        ctx.fill();

        // Center Monogram 'W'
        ctx.fillStyle = textColor;
        ctx.font = '900 130px ' + getComputedStyle(document.body).fontFamily;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('W', 0, 20);

        ctx.restore();

      } else {
        // --- BACK FACE: Denomination "10,000 TOKENS" ---
        // Guilloche Pattern Background
        ctx.save();
        ctx.strokeStyle = rimColor;
        ctx.lineWidth = 1.5;
        ctx.globalAlpha = 0.25;
        for (let i = 0; i < 36; i++) {
          const angle = (i / 36) * Math.PI * 2;
          ctx.beginPath();
          ctx.ellipse(cx, cy, 320, 120, angle, 0, Math.PI * 2);
          ctx.stroke();
        }
        ctx.restore();

        // Outer Arc Text
        drawArcText(ctx, "OFFICIAL MINT CERTIFIED", cx, cy, 380, -Math.PI * 0.75, -Math.PI * 0.25, textColor, shadowColor, 40);
        drawArcText(ctx, "ONE TROY OUNCE • .999 FINE", cx, cy, 380, Math.PI * 0.25, Math.PI * 0.75, textColor, shadowColor, 34);

        // Center Denomination Frame
        ctx.save();
        ctx.translate(cx, cy);

        ctx.fillStyle = textColor;
        ctx.shadowColor = shadowColor;
        ctx.shadowBlur = 12;
        ctx.shadowOffsetX = 4;
        ctx.shadowOffsetY = 6;

        // Octagonal Badge Box
        ctx.beginPath();
        const bw = 240, bh = 140, cr = 30;
        ctx.moveTo(-bw + cr, -bh);
        ctx.lineTo(bw - cr, -bh);
        ctx.lineTo(bw, -bh + cr);
        ctx.lineTo(bw, bh - cr);
        ctx.lineTo(bw - cr, bh);
        ctx.lineTo(-bw + cr, bh);
        ctx.lineTo(-bw, bh - cr);
        ctx.lineTo(-bw, -bh + cr);
        ctx.closePath();
        ctx.fill();

        // Inner Dark Inset
        ctx.fillStyle = baseGrad[2];
        ctx.beginPath();
        const ibw = 225, ibh = 125;
        ctx.moveTo(-ibw + cr, -ibh);
        ctx.lineTo(ibw - cr, -ibh);
        ctx.lineTo(ibw, -ibh + cr);
        ctx.lineTo(ibw, ibh - cr);
        ctx.lineTo(ibw - cr, ibh);
        ctx.lineTo(-ibw + cr, ibh);
        ctx.lineTo(-ibw, ibh - cr);
        ctx.lineTo(-ibw, -ibh + cr);
        ctx.closePath();
        ctx.fill();

        // Large Number: 10,000
        ctx.fillStyle = textColor;
        ctx.font = '900 82px ' + getComputedStyle(document.body).fontFamily;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('10,000', 0, -20);

        // Text: TOKENS
        ctx.font = '700 38px ' + getComputedStyle(document.body).fontFamily;
        ctx.letterSpacing = '0.1em';
