        ctx.restore();
      }

      return canvas;
    }

    function drawArcText(ctx, text, cx, cy, radius, startAngle, endAngle, color, shadowColor, fontSize) {
      ctx.save();
      ctx.font = `900 ${fontSize}px ` + getComputedStyle(document.body).fontFamily;
      ctx.fillStyle = color;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.shadowColor = shadowColor;
      ctx.shadowBlur = 8;
      ctx.shadowOffsetX = 3;
      ctx.shadowOffsetY = 4;

      const chars = text.split('');
      const n = chars.length;
      const angleStep = (endAngle - startAngle) / Math.max(1, n - 1);

      for (let i = 0; i < n; i++) {
        const angle = startAngle + i * angleStep;
        ctx.save();
        ctx.translate(cx + radius * Math.cos(angle), cy + radius * Math.sin(angle));
        ctx.rotate(angle + Math.PI / 2);
        ctx.fillText(chars[i], 0, 0);
        ctx.restore();
      }
      ctx.restore();
    }

    function drawStar(ctx, cx, cy, spikes, outerRadius, innerRadius, color) {
      let rot = Math.PI / 2 * 3;
      let x = cx;
      let y = cy;
      let step = Math.PI / spikes;

      ctx.beginPath();
      ctx.moveTo(cx, cy - outerRadius);
      for (let i = 0; i < spikes; i++) {
        x = cx + Math.cos(rot) * outerRadius;
        y = cy + Math.sin(rot) * outerRadius;
        ctx.lineTo(x, y);
        rot += step;

        x = cx + Math.cos(rot) * innerRadius;
        y = cy + Math.sin(rot) * innerRadius;
        ctx.lineTo(x, y);
        rot += step;
      }
      ctx.lineTo(cx, cy - outerRadius);
      ctx.closePath();
      ctx.fillStyle = color;
      ctx.fill();
    }

    /* =========================================================================
       3. WebGL Coin Renderer Engine
       ========================================================================= */
    const VS_SOURCE = `
      attribute vec3 aPosition;
      attribute vec3 aNormal;
      attribute vec2 aTexCoord;
      attribute float aMatType;

      uniform mat4 uMVMatrix;
      uniform mat4 uPMatrix;
      uniform mat3 uNMatrix;

      varying vec3 vNormal;
      varying vec3 vEyeVec;
      varying vec2 vTexCoord;
      varying float vMatType;

      void main(void) {
        vec4 mvPosition = uMVMatrix * vec4(aPosition, 1.0);
        gl_Position = uPMatrix * mvPosition;
        vNormal = uNMatrix * aNormal;
        vEyeVec = -mvPosition.xyz;
        vTexCoord = aTexCoord;
        vMatType = aMatType;
      }
    `;

    const FS_SOURCE = `
      precision highp float;

      varying vec3 vNormal;
      varying vec3 vEyeVec;
      varying vec2 vTexCoord;
      varying float vMatType;

      uniform sampler2D uFrontTexture;
      uniform sampler2D uBackTexture;
      uniform vec3 uBaseColor;
      uniform vec3 uSpecColor;

      void main(void) {
        vec3 N = normalize(vNormal);
        vec3 V = normalize(vEyeVec);

        // Relief Bump Mapping from Texture Luminance
        if (vMatType < 0.5) { // Front
          float hC = texture2D(uFrontTexture, vTexCoord).r;
          float hR = texture2D(uFrontTexture, vTexCoord + vec2(0.003, 0.0)).r;
          float hU = texture2D(uFrontTexture, vTexCoord + vec2(0.0, 0.003)).r;
          vec3 bump = vec3((hC - hR) * 3.5, (hC - hU) * 3.5, 1.0);
          N = normalize(N + bump * 0.4);
        } else if (vMatType < 1.5) { // Back
          float hC = texture2D(uBackTexture, vTexCoord).r;
          float hR = texture2D(uBackTexture, vTexCoord + vec2(0.003, 0.0)).r;
          float hU = texture2D(uBackTexture, vTexCoord + vec2(0.0, 0.003)).r;
          vec3 bump = vec3((hC - hR) * 3.5, (hC - hU) * 3.5, 1.0);
          N = normalize(N + bump * 0.4);
        }

        // Texture Sample
        vec4 texColor = vec4(1.0);
        if (vMatType < 0.5) {
          texColor = texture2D(uFrontTexture, vTexCoord);
        } else if (vMatType < 1.5) {
          texColor = texture2D(uBackTexture, vTexCoord);
        } else {
          texColor = vec4(uBaseColor, 1.0);
        }

        // Lights
        vec3 L1 = normalize(vec3(0.6, 0.8, 1.2));
        vec3 L2 = normalize(vec3(-0.8, -0.5, 0.6));

        // Diffuse
        float diff1 = max(dot(N, L1), 0.0);
        float diff2 = max(dot(N, L2), 0.0) * 0.3;

        // Specular Highlights (Blinn-Phong)
        vec3 H1 = normalize(L1 + V);
        vec3 H2 = normalize(L2 + V);
        float spec1 = pow(max(dot(N, H1), 0.0), 45.0);
        float spec2 = pow(max(dot(N, H2), 0.0), 20.0);

        // Metallic Environment Reflection Approximation
        vec3 R = reflect(-V, N);
        float env = pow(abs(R.y), 1.8) * 0.4 + pow(abs(R.x), 2.5) * 0.3 + 0.3;

        vec3 surfaceColor = texColor.rgb * uBaseColor;
        vec3 ambient = surfaceColor * 0.35;
        vec3 diffuse = surfaceColor * (diff1 * 0.65 + diff2 * 0.25);
        vec3 specular = uSpecColor * (spec1 * 1.4 + spec2 * 0.5) * (0.5 + env * 0.5);

        vec3 finalColor = ambient + diffuse + specular;

        // Tone Map
        finalColor = finalColor / (finalColor + vec3(0.75)) * 1.45;

        gl_FragColor = vec4(finalColor, 1.0);
      }
    `;

    function createCoinRenderer(canvas, metalType = 'gold') {
      const gl = canvas.getContext('webgl', { antialias: true, preserveDrawingBuffer: true }) ||
                 canvas.getContext('experimental-webgl', { antialias: true, preserveDrawingBuffer: true });

      if (!gl) return null;

      // Compile Shader Program
      function compileShader(src, type) {
        const s = gl.createShader(type);
        gl.shaderSource(s, src);
        gl.compileShader(s);
        return s;
      }
      const program = gl.createProgram();
      gl.attachShader(program, compileShader(VS_SOURCE, gl.VERTEX_SHADER));
      gl.attachShader(program, compileShader(FS_SOURCE, gl.FRAGMENT_SHADER));
      gl.linkProgram(program);
      gl.useProgram(program);

      // Locations
      const attribs = {
        aPosition: gl.getAttribLocation(program, 'aPosition'),
        aNormal: gl.getAttribLocation(program, 'aNormal'),
        aTexCoord: gl.getAttribLocation(program, 'aTexCoord'),
        aMatType: gl.getAttribLocation(program, 'aMatType')
      };
      const uniforms = {
        uMVMatrix: gl.getUniformLocation(program, 'uMVMatrix'),
        uPMatrix: gl.getUniformLocation(program, 'uPMatrix'),
        uNMatrix: gl.getUniformLocation(program, 'uNMatrix'),
        uFrontTexture: gl.getUniformLocation(program, 'uFrontTexture'),
        uBackTexture: gl.getUniformLocation(program, 'uBackTexture'),
        uBaseColor: gl.getUniformLocation(program, 'uBaseColor'),
        uSpecColor: gl.getUniformLocation(program, 'uSpecColor')
      };

      // Create Mesh Geometry (Front, Back, Reeded Edge)
      const positions = [];
      const normals = [];
      const texCoords = [];
      const matTypes = [];
      const indices = [];

      const R = 0.72;      // Radius (coin fits nicely inside viewport)
      const H = 0.08;      // Coin thickness
      const N_CAP = 120;   // Face resolution
      const N_REED = 160;  // Number of reeded ridges

      // Helper to add vertex
      let vertCount = 0;
      function addVertex(x, y, z, nx, ny, nz, u, v, mat) {
        positions.push(x, y, z);
        normals.push(nx, ny, nz);
        texCoords.push(u, v);
        matTypes.push(mat);
        return vertCount++;
      }

      // 1. Front Cap (z = +H/2)
      const centerFront = addVertex(0, 0, H/2, 0, 0, 1, 0.5, 0.5, 0.0);
      const frontRing = [];
      for (let i = 0; i <= N_CAP; i++) {
        const ang = (i / N_CAP) * Math.PI * 2;
        const x = R * Math.cos(ang);
        const y = R * Math.sin(ang);
        const u = 0.5 + 0.5 * Math.cos(ang);
        const v = 0.5 - 0.5 * Math.sin(ang);
        frontRing.push(addVertex(x, y, H/2, 0, 0, 1, u, v, 0.0));
      }
      for (let i = 0; i < N_CAP; i++) {
        indices.push(centerFront, frontRing[i], frontRing[i+1]);
      }

      // 2. Back Cap (z = -H/2)
      const centerBack = addVertex(0, 0, -H/2, 0, 0, -1, 0.5, 0.5, 1.0);
      const backRing = [];
      for (let i = 0; i <= N_CAP; i++) {
        const ang = (i / N_CAP) * Math.PI * 2;
        const x = R * Math.cos(ang);
        const y = R * Math.sin(ang);
        // Flipped u for readable back text when flipped
        const u = 0.5 - 0.5 * Math.cos(ang);
        const v = 0.5 - 0.5 * Math.sin(ang);
        backRing.push(addVertex(x, y, -H/2, 0, 0, -1, u, v, 1.0));
      }
      for (let i = 0; i < N_CAP; i++) {
        indices.push(centerBack, backRing[i+1], backRing[i]);
      }

      // 3. Reeded Rim (Edge Cylinder with alternating Ridges)
      for (let i = 0; i < N_REED; i++) {
        const a1 = (i / N_REED) * Math.PI * 2;
        const a2 = ((i + 1) / N_REED) * Math.PI * 2;

        const r1 = (i % 2 === 0) ? R : R * 0.975;
        const r2 = ((i + 1) % 2 === 0) ? R : R * 0.975;

        const x1_top = r1 * Math.cos(a1), y1_top = r1 * Math.sin(a1);
        const x1_bot = r1 * Math.cos(a1), y1_bot = r1 * Math.sin(a1);
        const x2_top = r2 * Math.cos(a2), y2_top = r2 * Math.sin(a2);
        const x2_bot = r2 * Math.cos(a2), y2_bot = r2 * Math.sin(a2);

        // Quad normal calculation
        const midA = (a1 + a2) / 2;
        const nx = Math.cos(midA);
        const ny = Math.sin(midA);

        const v0 = addVertex(x1_bot, y1_bot, -H/2, nx, ny, 0, 0, 0, 2.0);
        const v1 = addVertex(x1_top, y1_top,  H/2, nx, ny, 0, 0, 1, 2.0);
        const v2 = addVertex(x2_top, y2_top,  H/2, nx, ny, 0, 1, 1, 2.0);
        const v3 = addVertex(x2_bot, y2_bot, -H/2, nx, ny, 0, 1, 0, 2.0);

        indices.push(v0, v1, v2, v0, v2, v3);
      }

      // Create Buffers
      function createBuffer(target, data) {
        const buf = gl.createBuffer();
        gl.bindBuffer(target, buf);
        gl.bufferData(target, data, gl.STATIC_DRAW);
        return buf;
      }

      const vboPos = createBuffer(gl.ARRAY_BUFFER, new Float32Array(positions));
      const vboNorm = createBuffer(gl.ARRAY_BUFFER, new Float32Array(normals));
      const vboTex = createBuffer(gl.ARRAY_BUFFER, new Float32Array(texCoords));
      const vboMat = createBuffer(gl.ARRAY_BUFFER, new Float32Array(matTypes));
      const ibo = createBuffer(gl.ELEMENT_ARRAY_BUFFER, new Uint16Array(indices));

      // Upload Textures
      const frontCanvas = generateFaceTexture('front', metalType);
      const backCanvas = generateFaceTexture('back', metalType);

      function makeTexture(imageCanvas) {
        const tex = gl.createTexture();
        gl.bindTexture(gl.TEXTURE_2D, tex);
        gl.pixelStorei(gl.UNPACK_FLIP_Y_WEBGL, false);
        gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, imageCanvas);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR_MIPMAP_LINEAR);
        gl.generateMipmap(gl.TEXTURE_2D);
        return tex;
      }

      const frontTex = makeTexture(frontCanvas);
      const backTex = makeTexture(backCanvas);

      // Material Color Config
      let baseRGB = [0.95, 0.75, 0.25];
      let specRGB = [1.0, 0.95, 0.75];

      if (metalType === 'silver') {
        baseRGB = [0.85, 0.88, 0.92];
        specRGB = [1.0, 1.0, 1.0];
      } else if (metalType === 'bronze') {
        baseRGB = [0.80, 0.50, 0.25];
        specRGB = [0.95, 0.75, 0.55];
      } else if (metalType === 'black') {
        baseRGB = [0.15, 0.16, 0.20];
        specRGB = [0.95, 0.80, 0.30];
      }

      // Render Frame Function
      function render(t) {
        // Clamp t to [0,1]
        t = ((t % 1.0) + 1.0) % 1.0;

        gl.viewport(0, 0, canvas.width, canvas.height);
        gl.clearColor(0.04, 0.04, 0.06, 1.0);
        gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
        gl.enable(gl.DEPTH_TEST);

        // Rotation & Flip Math:
        // Full 360 deg Y-axis spin AND continuous horizontal X-axis flip
        const rotY = t * Math.PI * 2;
        const rotX = Math.sin(t * Math.PI * 2) * 0.55;
        const rotZ = Math.cos(t * Math.PI * 2) * 0.1;

        // Projection & ModelView Matrices
        const pMatrix = createMat4();
        perspectiveMat4(pMatrix, Math.PI / 4, canvas.width / canvas.height, 0.1, 100.0);

        const mvMatrix = createMat4();
        identityMat4(mvMatrix);
        mvMatrix[14] = -3.1; // Camera Distance Z

        const rx = createMat4(), ry = createMat4(), rz = createMat4();
        rotateXMat4(rx, null, rotX);
        rotateYMat4(ry, null, rotY);
        rotateXMat4(rz, null, rotZ);

        multiplyMat4(mvMatrix, mvMatrix, rx);
        multiplyMat4(mvMatrix, mvMatrix, ry);
        multiplyMat4(mvMatrix, mvMatrix, rz);

        const nMatrix = new Float32Array(9);
        mat3FromMat4(nMatrix, mvMatrix);

        // Bind Uniforms
        gl.uniformMatrix4fv(uniforms.uPMatrix, false, pMatrix);
        gl.uniformMatrix4fv(uniforms.uMVMatrix, false, mvMatrix);
        gl.uniformMatrix3fv(uniforms.uNMatrix, false, nMatrix);
        gl.uniform3fv(uniforms.uBaseColor, new Float32Array(baseRGB));
        gl.uniform3fv(uniforms.uSpecColor, new Float32Array(specRGB));

        // Textures
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, frontTex);
        gl.uniform1i(uniforms.uFrontTexture, 0);

        gl.activeTexture(gl.TEXTURE1);
        gl.bindTexture(gl.TEXTURE_2D, backTex);
        gl.uniform1i(uniforms.uBackTexture, 1);

