      letter-spacing: -0.02em;
      background: linear-gradient(135deg, #ffffff 30%, #a1a1aa 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
    }

    .hero-subtitle {
      font-size: 1.125rem;
      color: var(--text-muted);
      max-width: 520px;
    }

    @media (max-width: 968px) {
      .hero-subtitle {
        margin: 0 auto;
      }
    }

    .hero-specs {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 1rem;
      padding: 1.25rem 0;
      border-top: 1px solid rgba(255, 255, 255, 0.08);
      border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    }

    .spec-item {
      display: flex;
      flex-direction: column;
    }

    .spec-val {
      font-family: var(--font-mono);
      font-size: 1.1rem;
      font-weight: 700;
      color: var(--text-main);
    }

    .spec-lbl {
      font-size: 0.75rem;
      color: var(--text-muted);
      text-transform: uppercase;
      letter-spacing: 0.05em;
    }

    /* HERO CANVAS CONTAINER */
    .hero-canvas-container {
      position: relative;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
    }

    .canvas-wrapper {
      position: relative;
      width: 100%;
      max-width: 520px;
      aspect-ratio: 1;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    /* Simple subtle backdrop glow as specified */
    .canvas-wrapper::before {
      content: '';
      position: absolute;
      width: 75%;
      height: 75%;
      background: radial-gradient(circle, rgba(245, 158, 11, 0.12) 0%, rgba(0, 0, 0, 0) 70%);
      border-radius: 50%;
      z-index: 0;
      pointer-events: none;
    }

    #coin-hero {
      position: relative;
      z-index: 1;
      width: 100%;
      height: 100%;
      display: block;
    }

    .hero-controls {
      display: flex;
      gap: 0.5rem;
      margin-top: 1rem;
      background: rgba(18, 20, 28, 0.8);
      padding: 0.35rem;
      border-radius: 9999px;
      border: 1px solid rgba(255, 255, 255, 0.08);
    }

    .control-btn {
      background: transparent;
      border: none;
      color: var(--text-muted);
      padding: 0.4rem 0.85rem;
      border-radius: 9999px;
      font-size: 0.75rem;
      font-weight: 600;
      cursor: pointer;
      transition: all 0.2s;
    }

    .control-btn:hover {
      color: var(--text-main);
      background: rgba(255, 255, 255, 0.05);
    }

    .control-btn.active {
      background: rgba(255, 255, 255, 0.12);
      color: var(--text-main);
    }

    /* ABOUT SECTION */
    .about-section {
      max-width: 1280px;
      margin: 2rem auto 5rem;
      padding: 0 2rem;
    }

    .about-card {
      background: var(--bg-card);
      border: 1px solid var(--bg-card-border);
      border-radius: 24px;
      padding: 3.5rem 3rem;
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 3rem;
      align-items: center;
      position: relative;
      overflow: hidden;
    }

    @media (max-width: 868px) {
      .about-card {
        grid-template-columns: 1fr;
        padding: 2rem;
      }
    }

    .about-card::before {
      content: '';
      position: absolute;
      top: -50%;
      right: -20%;
      width: 400px;
      height: 400px;
      background: radial-gradient(circle, rgba(217, 119, 6, 0.08) 0%, rgba(0, 0, 0, 0) 70%);
      pointer-events: none;
    }

    .section-title {
      font-size: 2rem;
      font-weight: 800;
      margin-bottom: 1rem;
      letter-spacing: -0.01em;
    }

    .about-text {
      color: var(--text-muted);
      font-size: 1rem;
      line-height: 1.7;
    }

    .about-features {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1.5rem;
    }

    .feature-item {
      background: rgba(255, 255, 255, 0.02);
      border: 1px solid rgba(255, 255, 255, 0.05);
      padding: 1.25rem;
      border-radius: 16px;
    }

    .feature-item h4 {
      font-size: 0.95rem;
      font-weight: 700;
      margin-bottom: 0.35rem;
      color: var(--text-main);
    }

    .feature-item p {
      font-size: 0.825rem;
      color: var(--text-muted);
      line-height: 1.4;
    }

    /* COLLECTION GRID SECTION */
    .collection-section {
      max-width: 1280px;
      margin: 0 auto 6rem;
      padding: 0 2rem;
    }

    .section-header {
      text-align: center;
      max-width: 600px;
      margin: 0 auto 3.5rem;
    }

    .section-subtitle {
      color: var(--text-muted);
      font-size: 1rem;
      margin-top: 0.5rem;
    }

    .collection-grid {
      display: grid;
      grid-template-columns: repeat(4, 1fr);
      gap: 1.5rem;
    }

    @media (max-width: 1100px) {
      .collection-grid {
        grid-template-columns: repeat(2, 1fr);
      }
    }

    @media (max-width: 600px) {
      .collection-grid {
        grid-template-columns: 1fr;
      }
    }

    /* EXACT EDITION MARKUP REQUIRED */
    .edition {
      background: var(--bg-card);
      border: 1px solid var(--bg-card-border);
      border-radius: 20px;
      padding: 1.5rem;
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
      transition: transform 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease;
      position: relative;
    }

    .edition:hover {
      transform: translateY(-4px);
      border-color: rgba(255, 255, 255, 0.18);
      box-shadow: 0 12px 30px rgba(0, 0, 0, 0.4);
    }

    .edition-canvas-wrapper {
      position: relative;
      width: 100%;
      aspect-ratio: 1;
      margin-bottom: 1rem;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .edition-canvas {
      width: 100%;
      height: 100%;
      display: block;
    }

    .edition-header {
      width: 100%;
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 0.5rem;
    }

    .edition-name {
      font-size: 1.1rem;
      font-weight: 800;
      text-transform: capitalize;
    }

    .edition-price {
      font-family: var(--font-mono);
      font-weight: 700;
      font-size: 1rem;
      color: var(--text-main);
    }

    .edition-desc {
      font-size: 0.825rem;
      color: var(--text-muted);
      margin-bottom: 1.25rem;
      text-align: left;
      width: 100%;
      line-height: 1.4;
      flex-grow: 1;
    }

    /* STATUS BADGES & BUTTONS */
    .edition button.buy {
      width: 100%;
      background: linear-gradient(135deg, var(--accent-gold), #d97706);
      color: #000;
      border: none;
      padding: 0.75rem 1rem;
      border-radius: 12px;
      font-size: 0.875rem;
      font-weight: 800;
      letter-spacing: 0.02em;
      cursor: pointer;
      transition: opacity 0.2s, transform 0.1s;
      box-shadow: 0 4px 14px var(--accent-gold-glow);
    }

    .edition button.buy:hover {
      opacity: 0.92;
      transform: scale(0.99);
    }

    .status-pill {
      width: 100%;
      padding: 0.75rem 1rem;
      border-radius: 12px;
      font-size: 0.825rem;
      font-weight: 800;
      letter-spacing: 0.05em;
      text-transform: uppercase;
      text-align: center;
    }

    .status-pill.sold-out {
      background: rgba(239, 68, 68, 0.1);
      border: 1px solid rgba(239, 68, 68, 0.25);
      color: #f87171;
    }

    .status-pill.coming-soon {
      background: rgba(56, 189, 248, 0.1);
      border: 1px solid rgba(56, 189, 248, 0.25);
      color: #38bdf8;
    }

    /* FOOTER */
    footer {
      border-top: 1px solid rgba(255, 255, 255, 0.06);
      padding: 3rem 2rem;
      text-align: center;
      color: var(--text-muted);
      font-size: 0.85rem;
    }

    .footer-content {
      max-width: 1280px;
      margin: 0 auto;
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 1rem;
    }

    /* TOAST NOTIFICATION */
    .toast {
      position: fixed;
      bottom: 2rem;
      right: 2rem;
      background: rgba(18, 20, 28, 0.95);
      border: 1px solid var(--accent-gold);
      color: var(--text-main);
      padding: 1rem 1.5rem;
      border-radius: 14px;
      font-size: 0.9rem;
      font-weight: 600;
      box-shadow: 0 10px 30px rgba(0,0,0,0.5);
      z-index: 1000;
      opacity: 0;
      transform: translateY(20px);
      transition: all 0.3s ease;
      pointer-events: none;
    }

    .toast.show {
      opacity: 1;
      transform: translateY(0);
    }
  </style>
</head>
